1	import { _decorator, error, log } from "cc";
2	import GameView from "../GameView";
3	import { BaseState, commonGameManager, eventManager, msgBoxManager, newBottombarManager, newExtraManager, stateManager } from "db://astarte-framework/Managers";
4	import { CommonState, Define } from "db://astarte-framework/utilis";
5	import { FeverGameType } from "../Game_Define";
6	import { GAME_INTRO_MANAGER_EVENT } from "../GameIntroManager";
7	import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
8	import { REEL_UI_MANAGER_EVENT, UIType } from "../Reel/ReelManager";
9	import { FREE_GAME_UI_MANAGER_EVENT } from "../FreeGame/FreeGameUIManager";
10	import { BACKGROUND_MANAGER_EVENT, BackgroundType } from "../BackgroundManager";
11	import { WANTED_POSTER_MANAGER_EVENT } from "../WantedPoster/WantedPosterManager";
12	import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";
13	
14	const { ccclass } = _decorator;
15	
16	@ccclass( "UnshowPrepareState" )
17	export class UnshowPrepareState extends BaseState
18	{
19	    private m_gameView: GameView = null;
20	
21	    /** @ch 起始盤面索引 */
22	    private m_startRound: number = 0;
23	
24	    /** @ch 起始盤面資訊 */
25	    private m_startRoundInfo: protocol.ar2pq9Proto.IRoundInfo = null;
26	
27	    /** @ch 要還原的盤面資料 */
28	    private m_unshowSpinAckQue: protocol.ar2pq9Proto.IRoundInfo[] = [];
29	
30	    /** @ch 上一輪累積贏分 */
31	    private m_previousAccumulatedWinValue: number = 0;
32	
33	    constructor( gameView: GameView )
34	    {
35	        super();
36	        this.m_gameView = gameView;
37	    }
38	
39	    public async OnEnter()
40	    {
41	        log( "OnEnter State : UnshowPrepare" );
42	        if ( !commonGameManager.HasUnshow )
43	        {
44	            return;
45	        }
46	
47	        newExtraManager.HasUnshow = false;
48	        
49	        newBottombarManager.SetBarNodeVisiable( true );
50	        eventManager.Dispatch( GAME_INTRO_MANAGER_EVENT.HIDE_NODE );
51	        this.m_unshowSpinAckQue = this.m_gameView.UnshowSpinAck.RoundQueue ?? [];
52	        this.m_startRound = Math.trunc(commonGameManager.UnshowStartRound ?? 0);
53	
54	        // 如果有多個盤面資料，則選擇要還原的盤面
55	        if (this.m_unshowSpinAckQue.length > 0) {
56	            const lastIndex = this.m_unshowSpinAckQue.length - 1;
57	            if (this.m_startRound < 0 || this.m_startRound > lastIndex) {
58	                error(`[UnshowPrepareState] startRound (${this.m_startRound}) out of range [0, ${lastIndex}]`);
59	                this.m_startRound = Math.min(Math.max(0, this.m_startRound), lastIndex);
60	            }
61	            this.m_gameView.CurRoundIndex = this.m_startRound;
62	            this.m_startRoundInfo = this.m_unshowSpinAckQue[this.m_startRound];
63	        }
64	        else {
65	            error("[UnshowPrepareState] RoundQueue is empty");
66	            this.m_startRound = 0;
67	            this.m_gameView.CurRoundIndex = 0;
68	            this.m_startRoundInfo = null;
69	        }
70	
71	        this.m_previousAccumulatedWinValue = 0;
72	
73	        if (
74	            this.m_unshowSpinAckQue.length > 1
75	            && this.m_startRound >= 1
76	        ) {
77	            if (this.m_startRoundInfo.CurrFeverGameType === FeverGameType.FreeGame) {
78	                this.m_gameView.IsFreeGame = true;
79	                this.m_gameView.IsFirstRound = false;
80	
81	                // 還原 FreePickItems（unshow startRound>=1 時 OnRecvSpinAck 不會設定）
82	                const firstRound = this.m_unshowSpinAckQue[0];
83	                if (firstRound?.FreePickItem && (firstRound.FreePickItem as number[]).length > 0) {
84	                    this.m_gameView.FreePickItems = firstRound.FreePickItem as number[];
85	                }
86	
87	                let isUseCreateFreeGamePlate = false;
88	
89	                // 用上一局的 FeverTotalRound（加局前的值），讓本局 +spin 判定能正常觸發
90	                const prevRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
91	                this.m_gameView.FreeTotalRound = prevRoundInfo ? prevRoundInfo.FeverTotalRound : this.m_startRoundInfo.FeverTotalRound;
92	                eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_REMAINING_ROUND, 
93	                    this.m_startRoundInfo.FeverNowRound - 1, 
94	                    this.m_gameView.FreeTotalRound);
95	                //this.m_gameView.FgCounter.SetCounter( remainRound, this.m_gameView.FreeTotalRound );
96	                // 如果目前是免費遊戲，且免費遊戲回合數為0，則需要重新建立免費遊戲盤面
97	                if (this.m_startRoundInfo.FeverNowRound <= 0) {
98	                    isUseCreateFreeGamePlate = true;
99	                } else {
100	                    // 取得上一輪盤面資料
101	                    const previousRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
102	                    let previousPlateInfo = null;
103	                    if (previousRoundInfo && previousRoundInfo.PlateQueue.length > 0) {
104	                        // 取得上一輪最後一個盤面資料
105	                        previousPlateInfo = previousRoundInfo.PlateQueue[previousRoundInfo.PlateQueue.length - 1];
106	
107	                        // 設定盤面資料
108	                        this.m_gameView.SlotReels.SetPlateInfoForUnshow(previousPlateInfo, false);
109	
110	                        // 設置懸賞令資料（還原 → isNewRound=true 整批重建）
111	                        eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, previousPlateInfo?.BountyDataVec || [], true);
112	                    }
113	                    // 如果上一輪盤面資料不存在，則需要重新建立免費遊戲盤面 照理說不會發生，但還是加上去
114	                    else {
115	                        isUseCreateFreeGamePlate = true;
116	                    }
117	                }
118	
119	                // 如果需要重新建立免費遊戲盤面，則建立免費遊戲盤面
120	                if (isUseCreateFreeGamePlate) {
121	                    this.m_gameView.SlotReels.SetFreeGamePlate();
122	                }
123	            }
124	            else {
125	                // MG 模式：恢復上一輪最終盤面（tumble 消除補位後的結果）
126	                const previousRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
127	                if (previousRoundInfo && previousRoundInfo.PlateQueue && previousRoundInfo.PlateQueue.length > 0) {
128	                    const previousPlateInfo = previousRoundInfo.PlateQueue[previousRoundInfo.PlateQueue.length - 1];
129	                    this.m_gameView.SlotReels.SetPlateInfoForUnshow(previousPlateInfo, false);
130	                    // 還原 → isNewRound=true 整批重建
131	                    eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, previousPlateInfo?.BountyDataVec || [], true);
132	                }
133	            }
134	
135	            // 計算上一輪累積贏分
136	            for (let i = 0; i < this.m_startRound; i++) {
137	                this.m_previousAccumulatedWinValue += this.m_unshowSpinAckQue[i].RoundWin;
138	            }
139	        }
140	
141	        // 恢復UI
142	        await this.RestoreUI();
143	
144	        // ExtraBet 僅主遊戲顯示，此路徑繞過 EnterFreeState；須在 RestoreUI 之後隱藏，
145	        // 避免 RestoreExtraBetState 的動畫在 inactive node 上 await 不 resolve
146	        if ( this.m_gameView.IsFreeGame ) {
147	            this.m_gameView.SetExtraBetVisible( false );
148	        }
149	
150	        // 恢復背景音樂
151	        this.RestoreBgm();
152	
153	        msgBoxManager.ShowMessageBox(
154	            Define.StringKey.MSGBOX_UNSHOW_BACK,
155	            Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO,
156	            () => {
157	                stateManager.NextState(CommonState.SPIN);
158	            }
159	        );
160	    }
161	
162	    public OnProcess()
163	    {
164	    }
165	
166	    public OnLeave()
167	    {
168	        this.m_startRoundInfo = null;
169	        this.m_previousAccumulatedWinValue = 0;
170	    }
171	
172	    /**
173	     * @ch 恢復免費遊戲UI
174	     */
175	    private RestoreFreeGameUI()
176	    {
177	        // 設定下bar為免費遊戲狀態
178	        newBottombarManager.SetEnterFree();
179	
180	        // 切換到免費遊戲UI
181	        eventManager.Dispatch( REEL_UI_MANAGER_EVENT.CHANGE_UI, UIType.FreeGame );
182	        eventManager.Dispatch( BACKGROUND_MANAGER_EVENT.CHANGE_BACKGROUND, BackgroundType.FreeGame );
183	
184	        // 還原 feature icon 狀態
185	        if (this.m_gameView.FreePickItems && this.m_gameView.FreePickItems.length > 0) {
186	            if (this.m_gameView.FeatureIconSpineNode) this.m_gameView.FeatureIconSpineNode.active = true;
187	            eventManager.Dispatch(FREE_GAME_UI_MANAGER_EVENT.SET_ACTIVE_FEATURES, this.m_gameView.FreePickItems);
188	        }
189	
190	        // 還原 symbol 底板（MultiplierBase）
191	        if (this.m_startRound >= 1) {
192	            const previousRoundInfo = this.m_unshowSpinAckQue[this.m_startRound - 1];
193	            if (previousRoundInfo && previousRoundInfo.PlateQueue && previousRoundInfo.PlateQueue.length > 0) {
194	                const lastPlate = previousRoundInfo.PlateQueue[previousRoundInfo.PlateQueue.length - 1];
195	                if (lastPlate.BasePlateIndex && lastPlate.BasePlateIndex.length > 0) {
196	                    // 展平 IIntAry[] → number[]（col-major: col0row0, col0row1, ... col1row0, ...）
197	                    const flatList: number[] = [];
198	                    for (const col of lastPlate.BasePlateIndex) {
199	                        if (col.Data) {
200	                            for (const val of col.Data) {
201	                                flatList.push(val);
202	                            }
203	                        }
204	                    }
205	                    eventManager.Dispatch(MULTIPLIER_BASE_MANAGER_EVENT.SET_SHOW, -1, true);
206	                    eventManager.Dispatch(MULTIPLIER_BASE_MANAGER_EVENT.SET_MULTIPLIER_LIST, flatList);
207	                }
208	            }
209	        }
210	    }
211	
212	    /**
213	     * @ch 恢復所有UI
214	     */
215	    private async RestoreUI()
216	    {
217	        if (this.m_gameView.IsFreeGame) {
218	            this.RestoreFreeGameUI();
219	        }
220	
221	        this.RestoreWinValue();
222	
223	        if (this.m_gameView.UnshowSpinAck != null && commonGameManager.UnshowBaseBet < commonGameManager.UnshowRealBet) {
224	            await this.m_gameView.RestoreExtraBetState();
225	        }
226	    }
227	
228	    /**
229	     * @ch 恢復贏分
230	     */
231	    private RestoreWinValue()
232	    {
233	
234	        const totalWin = this.m_gameView.UnshowSpinAck?.TotalWin ?? 0;
235	        this.m_gameView.AccumulatedWin = this.m_previousAccumulatedWinValue;
236	        newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: this.m_gameView.AccumulatedWin } );
237	    }
238	
239	    /**
240	     * @ch 恢復背景音樂
241	     */
242	    private RestoreBgm()
243	    {
244	        this.m_gameView.PlayMainGameBgm();
245	        if (this.m_gameView.IsFreeGame) {
246	            this.m_gameView.PauseMainGameBgm();
247	            this.m_gameView.PlayFreeGameBgm();
248	        }
249	    }
250	}

