async ForceSetExtraBet( isActive: boolean, type: number = TYPE.Special )
{
    if ( tools.CheckSwitchOff( SwitchOffKeyDefine.CloseExtraBet ) )
    {
        return;
    }
    this.m_usedForce = true;
    if ( isActive )
    {
        this.m_isForceExtraOnEnd = false;
        this.m_isExtra = true;
        if ( this.m_multiBtn_on.length == 1 )
        {
            this.m_multiBtn_on[ 0 ].node.active = true;
            this.m_multiBtn_off[ 0 ].node.active = false;
        }

        // if ( this.m_isTwoStep )
        // {
        //     this.m_toStepTwo = true;
        //     this.SetTwoStepMulti( isActive, type );
        // }
        // else
        // {
        newBottombarManager.ChangeMultiBet( type );
        // }
        await this.m_triggerCb( isActive, true );
        this.m_ExtraBetAniPlaying = true;
        await this.PlayAnimation( this.m_multiExtraBetNode.getComponent( Animation ), "ExtraBet_Close" );
        if ( this.m_multiExtraBetNode )
        {
            this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Active" );
        }
        this.m_ExtraBetAniPlaying = false;
        this.m_isForceExtraOnEnd = true;
    }
    else
    {
        if ( this.m_isExtra ) // 有被啟動過才需要關閉
        {
            let promises = [];

            this.m_isExtra = false;
            if ( this.m_multiBtn_on.length == 1 )
            {
                this.m_multiBtn_on[ 0 ].node.active = false;
                this.m_multiBtn_off[ 0 ].node.active = true;
            }
            newBottombarManager.ChangeMultiBet( TYPE.Normal );
            // 這邊要確保特效被完全關掉
            if ( this.m_multiExtraBetNode )
            {
                if ( !this.m_isExtendShowBar )
                {
                    promises.push( this.PlayAnimation( this.m_multiExtraBetNode.getComponent( Animation ), ( "ExtraBet_OFF" ) ) );
                }
                else
                {
                    promises.push( this.ExtendShowBar( false ) );
                }
            }
            promises.push( this.m_triggerCb( isActive, true ) );
            await Promise.all( promises );
        }
    }

}

OnRotation()
{
    if ( tools.CheckSwitchOff( SwitchOffKeyDefine.CloseExtraBet ) )
    {
        return;
    }
    if ( this.m_multiExtraBetNode )
    {
        if ( this.m_isExtra )
        {
            this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Active" );
        }
        else
        {
            // 動畫ExtraBet_Stop 是橫版...
            this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Stop" );
        }
    }
    if ( this.m_multiBtn_Tip )
    {
        this.m_multiBtn_Tip.active = false;
    }
}

// 檢查EX 的動畫是否撥放中 點按鈕可不可以被打斷
IsExAnimationTouchable(): boolean
{
    return !this.m_ExtraBetAniPlaying;
}

/** 進遊戲時主動彈出EX BAR與說明 (有需要在自行呼叫) */
async FirstShowBar()
{
    if ( !this.m_isFirstShowed && !this.m_usedForce &&
        !tools.CheckSwitchOff( SwitchOffKeyDefine.CloseExtraBet ) &&
        !Define.HAS_REPLAY )
    {
        this.m_isFirstShowed = true;
        await this.ExtendShowBar( true );
        if ( this.m_multiBtn_Tip )
        {
            this.m_multiBtn_Tip.active = true;
        }
        this.m_firstShowBarTween =
            tween( this.node )
                .delay( DELAYTIME.EXTRABET_FITST_SHOW_CLOSE )
                .call( () =>
                {
                    this.ExtendShowBar( false );
                } )
                .start();
    }

