    private PlayAnimation( animation: Animation, aniName: string, loop: boolean = false ): Promise<boolean>
    {
        return new Promise<boolean>( resolve =>
        {
            animation.play( aniName );
            if ( loop )
            {
                let state = animation.getState( aniName );
                if ( state )
                {
                    state.wrapMode = AnimationClip.WrapMode.Loop;
                }
            }

            animation.once( Animation.EventType.FINISHED, () =>
            {
                resolve( true );
            } );
        } );
    }
}

