private async ChangeBetMode()
{
    if ( tools.CheckSwitchOff( SwitchOffKeyDefine.CloseExtraBet ) )
    {
        return;
    }
    log( "ChangeBetMode stateManager.Current() : ", stateManager.Current() );
    if ( newBottombarManager && !buyBonusManager.IsBuyBonus &&
        ( stateManager.Current() === CommonState.IDLE || this.m_isExtra ) )
    {
        if ( !newBottombarManager.CheckExtraBetMaxBet( TYPE.Special ) )
        {
            msgBoxManager.ShowMessageBox( Define.StringKey.MSGBOX_BET_LIMIT_1 );
            return;
        }

        this.m_isExtra = !this.m_isExtra;
        let promises = [];

        if ( this.m_isExtra )
        {
            // 啟用 Extra 時一律關閉說明
            if ( this.m_firstShowBarTween !== null )
            {
                this.m_firstShowBarTween.stop();
                this.m_firstShowBarTween = null;
            }
            if ( this.m_multiBtn_Tip )
            {
                this.m_multiBtn_Tip.active = false;
            }


            if ( this.m_isTwoStep )
            {
                this.m_toStepTwo = true;
            }
            else
            {
                newBottombarManager.ChangeMultiBet( TYPE.Special );
            }

            if ( this.m_multiBtn_on.length == 1 )
            {
                this.m_multiBtn_on[ 0 ].node.active = true;
                this.m_multiBtn_off[ 0 ].node.active = false;
            }
            this.m_ExtraBetAniPlaying = true;

            newBottombarManager?.SetSpinState( SlotBottomBarState.CLICK_SPIN );
            newExtraManager?.SetBuyBonusState( false );
            if ( this.m_multiExtraBetNode &&
                Define.NOW_GAME_ID != "109" )
            {
                promises.push( this.PlayAnimation( this.m_multiExtraBetNode.getComponent( Animation ), "ExtraBet_ON" ) );
            }
            promises.push( this.m_triggerCb( this.m_isExtra, false ) );
            await Promise.all( promises );
            this.m_ExtraBetAniPlaying = false;
            newBottombarManager?.SetSpinState( SlotBottomBarState.IDLE );
            if ( this.m_multiExtraBetNode )
            {
                this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Active" );
            }
            await Define.Wait( this, 0.2 );
            newExtraManager?.SetBuyBonusState( true );
            // tween( this.node )
            //     .call( () =>
            //     {
            //         // 規格：切換模式 不能同時點選地bar
            //         if ( newBottombarManager )
            //         {
            //             newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_SPIN );
            //         }
            //         // ExtraBet 按鈕開啟/全版宣告動畫
            //         this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_ON" );
            //         this.m_gameView.EffectAward.Show_ExtraBet_Declare( () =>
            //         {
            //             this.ExtraBetAniPlaying = false;
            //         } );
            //     } )
            //     .delay( DELAYTIME.EXTRABET_ON )
            //     .call( () =>
            //     {
            //         this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Active" );
            //     } )
            //     .start();
        }
        else
        {
            newBottombarManager.ChangeMultiBet( TYPE.Normal );

            if ( this.m_multiBtn_on.length == 1 )
            {
                this.m_multiBtn_on[ 0 ].node.active = false;
                this.m_multiBtn_off[ 0 ].node.active = true;
            }
            this.m_ExtraBetAniPlaying = true;

            newBottombarManager?.SetSpinState( SlotBottomBarState.CLICK_SPIN );
            if ( this.m_multiExtraBetNode )
            {
                promises.push( this.PlayAnimation( this.m_multiExtraBetNode.getComponent( Animation ), "ExtraBet_OFF" ) );
            }
            promises.push( this.m_triggerCb( this.m_isExtra, false ) );
            await Promise.all( promises );
            this.m_ExtraBetAniPlaying = false;
            newBottombarManager?.SetSpinState( SlotBottomBarState.IDLE );

            // tween( this.node )
            //     .call( () =>
            //     {
            //         // 規格：切換模式 不能同時點選地bar
            //         if ( newBottombarManager )
            //         {
            //             newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_SPIN );
            //         }
            //         // ExtraBet 按鈕關閉/版面關閉動畫
            //         this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_OFF" );
            //         this.m_gameView.EffectAward.Show_ExtraBet_Close( () =>
            //         {
            //             this.ExtraBetAniPlaying = false;
            //         } );

            //     } )
            //     .delay( DELAYTIME.EXTRABET_OFF )
            //     .call( () =>
            //     {
            //         if ( newBottombarManager )
            //         {
            //             newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
            //         }
            //     } )
            //     .start();
        }
    }
    else if ( stateManager.Current() !== CommonState.IDLE )
    {
        log( "TRIAL_REFUSED_REASON 1 " );
        msgBoxManager.ShowMessageBox( Define.StringKey.FREEWINCASH_PLAYING1 );
    }
}

