72	    /** @ch 三個項目的選中框節點（順序對應卡片 0/1/2），預設 inactive */
73	    @property( {
74	        type: Node,
75	        tooltip: "三個項目的選中框節點（順序對應卡片 0/1/2），預設 inactive"
76	    } )
77	    private m_itemSelectFrames: Node[] = [];
