79	    /** @ch 三個項目的點擊區按鈕（順序對應卡片 0/1/2） */
80	    @property( {
81	        type: Button,
82	        tooltip: "三個項目的點擊區按鈕（順序對應卡片 0/1/2）"
83	    } )
84	    private m_itemBtns: Button[] = [];
