125	    private m_waitResolve: ( ( result: ExtraBetWindowResult ) => void ) | null = null;
126	    //#endregion 私有變數
127	
128	    //#region 方法
129	    /**
130	     * @ch 初始化跳窗（在 InitExtraBet 時呼叫）
131	     * @param multiplierRates 三個卡片的倍率陣列，Label 顯示值 = Bet × rate
132	     */
133	    Init( multiplierRates: number[] )
134	    {
135	        // BetList 在 ShowAndWait 時才同步（start 初期 newBottombarManager 可能尚未就緒）
136	        this.m_multiplierRates = multiplierRates;
137	    }
138	
139	    /** @ch 綁定所有按鈕的觸控事件 */
140	    onLoad()
141	    {
142	        this.m_addBtn?.node.on( Node.EventType.TOUCH_END, this.AddBet, this );
143	        this.m_subBtn?.node.on( Node.EventType.TOUCH_END, this.SubBet, this );
