146	        for ( let i = 0; i < this.m_itemBtns.length; i++ )
147	        {
148	            const idx = i;
149	            this.m_itemBtns[ i ]?.node.on( Node.EventType.TOUCH_END, () => this.SelectItem( idx ), this );
150	        }
151	    }
152	
153	    /** @ch 解綁所有按鈕的觸控事件，避免記憶體洩漏 */
154	    onDestroy()
155	    {
156	        this.StopLightBreathing();
157	        this.m_addBtn?.node.off( Node.EventType.TOUCH_END, this.AddBet, this );
158	        this.m_subBtn?.node.off( Node.EventType.TOUCH_END, this.SubBet, this );
159	        this.m_confirmBtn?.node.off( Node.EventType.TOUCH_END, this.OnConfirm, this );
160	        this.m_closeBtn?.node.off( Node.EventType.TOUCH_END, this.OnClose, this );
161	        for ( let i = 0; i < this.m_itemBtns.length; i++ )
162	        {
163	            this.m_itemBtns[ i ]?.node.targetOff( this );
164	        }
165	    }
166	
167	    /**
168	     * @ch 顯示跳窗，等使用者按 Confirm 或 × 後回傳結果。
169	     * @param triggerCb 應 await 此方法，保持 m_ExtraBetAniPlaying=true 直到使用者操作完畢。
170	     */
171	    async ShowAndWait(): Promise<ExtraBetWindowResult>
172	    {
173	        // 若已有等待中的 resolve，先以取消結果回傳，避免懸掛 Promise
174	        if ( this.m_waitResolve )
175	        {
176	            this.m_waitResolve( { confirmed: false, type: 0 } );
177	            this.m_waitResolve = null;
178	        }
179	
180	        if ( !this.m_viewNode.active )
181	        {
182	            await this.Show();
183	        }
184	        return new Promise<ExtraBetWindowResult>( ( resolve ) =>
185	        {
186	            this.m_waitResolve = resolve;
187	        } );
188	    }
189	
190	    /**
191	     * @ch 播放開啟動畫並顯示介面，重置選中狀態與同步最新 BetList。
192	     * 動畫播放中或介面已顯示時直接 return。
193	     */
194	    private async Show()
195	    {
196	        const hideState = this.m_anim?.getState( AnimName.Hide );
197	        if ( this.m_isPlayingAnim || this.m_viewNode.active || hideState?.isPlaying ) return;
198	
199	        // 重置選中狀態，同步最新 BetList
200	        this.m_selectedIndex = -1;
201	        this.UpdateSelectFrames();
202	        this.m_betList = newBottombarManager.GetBetList().slice();
203	        this.m_betIdx = newBottombarManager.GetNowBetIndex();
204	        if ( this.m_betIdx >= this.m_betList.length )
205	        {
206	            this.m_betIdx = this.m_betList.length - 1;
207	        }
208	        this.SetPrice();
209	
210	        Tween.stopAllByTarget( this.node );
211	        this.m_isPlayingAnim = true;
212	        this.m_viewNode.active = true;
213	        this.m_anim?.play( AnimName.Show );
214	        const showState: AnimationState = this.m_anim?.getState( AnimName.Show );
215	        if ( showState )
216	        {
217	            await Define.Wait( this, showState.duration );
218	        }
219	        this.m_isPlayingAnim = false;
220	        this.StartLightBreathing();
221	    }
222	
223	    /**
224	     * @ch 播放關閉動畫並隱藏介面。
