231	
232	        const showState = this.m_anim?.getState( AnimName.Show );
233	        if ( showState?.isPlaying )
234	        {
235	            showState.stop();
236	            this.m_isPlayingAnim = false;
237	        }
238	
239	        this.StopLightBreathing();
240	        Tween.stopAllByTarget( this.node );
241	        this.m_isPlayingAnim = true;
242	        this.m_anim?.play( AnimName.Hide );
243	        const playingHideState = this.m_anim?.getState( AnimName.Hide );
244	        if ( playingHideState )
245	        {
246	            await Define.Wait( this, playingHideState.duration );
247	        }
248	        this.m_viewNode.active = false;
249	        this.m_isPlayingAnim = false;
250	    }
