265	        AudioManager.Play( Define.AudioClips.COMMON_BTN );
266	        this.m_betIdx--;
267	        this.SetPrice();
268	    }
269	
270	    /**
271	     * @ch 根據當前 m_betIdx 更新 Bet Label 與三個卡片的金額 Label。
