282	        {
283	            if ( this.m_itemLabels[ i ] && this.m_multiplierRates[ i ] !== undefined )
284	            {
285	                const value = tools.times( bet, this.m_multiplierRates[ i ] );
286	                this.m_itemLabels[ i ].string = tools.FormatNumberThousands( value, tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT );
287	            }
288	        }
289	    }
290	
291	    /**
292	     * @ch 選中指定卡片並更新選中框顯示。
293	     * 若點擊已選中的卡片則忽略（避免重複音效與重繪）。
294	     * @param index 卡片索引（0-based）
295	     */
296	    private SelectItem( index: number )
297	    {
298	        if ( this.m_selectedIndex === index ) return;
299	        AudioManager.Play( Define.AudioClips.COMMON_BTN );
300	        this.m_selectedIndex = index;
301	        this.UpdateSelectFrames();
302	    }
303	
304	    /** @ch 依 m_selectedIndex 更新所有卡片選中框的 active 狀態（只顯示選中項） */
305	    private UpdateSelectFrames()
306	    {
307	        for ( let i = 0; i < this.m_itemSelectFrames.length; i++ )
308	        {
309	            if ( this.m_itemSelectFrames[ i ] )
310	            {
311	                this.m_itemSelectFrames[ i ].active = ( i === this.m_selectedIndex );
312	            }
313	        }
314	    }
315	
316	    /**
317	     * @ch 啟動 m_lightNode 的呼吸動畫（參數見 LightBreathing 常數）。
318	     * 啟動前先清理舊 tween 並重置 scale，避免重複啟動造成抖動。
319	     */
320	    private StartLightBreathing()
321	    {
322	        if ( !this.m_lightNode ) return;
323	        const { HalfCycleSec, MinScale, MaxScale } = LightBreathing;
324	        Tween.stopAllByTarget( this.m_lightNode );
325	        this.m_lightNode.setScale( MinScale, MinScale, MinScale );
326	        tween( this.m_lightNode )
327	            .to( HalfCycleSec, { scale: new Vec3( MaxScale, MaxScale, MaxScale ) }, { easing: "sineInOut" } )
328	            .to( HalfCycleSec, { scale: new Vec3( MinScale, MinScale, MinScale ) }, { easing: "sineInOut" } )
329	            .union()
330	            .repeatForever()
331	            .start();
332	    }
333	
334	    /** @ch 停止 m_lightNode 的呼吸動畫並重置 scale 為 MinScale。 */
335	    private StopLightBreathing()
336	    {
337	        if ( !this.m_lightNode ) return;
338	        const { MinScale } = LightBreathing;
339	        Tween.stopAllByTarget( this.m_lightNode );
340	        this.m_lightNode.setScale( MinScale, MinScale, MinScale );
341	    }
342	
343	    /**
