import { _decorator, Animation, AnimationState, Button, Component, Label, Node, Tween, tween, Vec3 } from "cc";
import { newBottombarManager } from "db://astarte-framework/Managers";
import { Define, tools } from "db://astarte-framework/utilis";
import { AudioManager } from "../Audio/AudioManager";

const { ccclass, property } = _decorator;

const AnimName = {
    Show: "ExtraBetWindow_Open",
    Hide: "ExtraBetWindow_Close",
};

/** @ch m_lightNode 呼吸動畫參數（scale 在 MinScale ↔ MaxScale 之間循環，單向耗時 HalfCycleSec） */
const LightBreathing = {
    HalfCycleSec: 1.2,
    MinScale: 1.0,
    MaxScale: 1.1,
};

export interface ExtraBetWindowResult
{
    confirmed: boolean;
    type: number;  // 選中卡片 index+1；0=未選/取消
}

@ccclass( "ExtraBetWindow" )
export class ExtraBetWindow extends Component
{
    //#region 屬性
    /** @ch 介面根節點（控制顯示隱藏） */
    @property( {
        type: Node,
        tooltip: "介面根節點（控制顯示隱藏）"
    } )
    private m_viewNode: Node = null;

    /** @ch 介面開關動畫 */
    @property( {
        type: Animation,
        tooltip: "介面開關動畫"
    } )
    private m_anim: Animation = null;

    /** @ch 當前 Bet 顯示 Label */
    @property( {
        type: Label,
        tooltip: "當前 Bet 顯示 Label"
    } )
    private m_betLabel: Label = null;

    /** @ch 增加 Bet 按鈕（+） */
    @property( {
        type: Button,
        tooltip: "增加 Bet 按鈕（+）"
    } )
    private m_addBtn: Button = null;

    /** @ch 減少 Bet 按鈕（-） */
    @property( {
        type: Button,
        tooltip: "減少 Bet 按鈕（-）"
    } )
    private m_subBtn: Button = null;

    /** @ch 三個項目的金額 Label（順序對應卡片 0/1/2），顯示 Bet × 倍率 */
    @property( {
        type: Label,
        tooltip: "三個項目的金額 Label（順序對應卡片 0/1/2），顯示 Bet × 倍率"
    } )
    private m_itemLabels: Label[] = [];

    /** @ch 三個項目的選中框節點（順序對應卡片 0/1/2），預設 inactive */
    @property( {
        type: Node,
        tooltip: "三個項目的選中框節點（順序對應卡片 0/1/2），預設 inactive"
    } )
    private m_itemSelectFrames: Node[] = [];

    /** @ch 三個項目的點擊區按鈕（順序對應卡片 0/1/2） */
    @property( {
        type: Button,
        tooltip: "三個項目的點擊區按鈕（順序對應卡片 0/1/2）"
    } )
    private m_itemBtns: Button[] = [];

    /** @ch 確認按鈕 */
    @property( {
        type: Button,
        tooltip: "確認按鈕"
    } )
    private m_confirmBtn: Button = null;

    /** @ch 關閉按鈕（×） */
    @property( {
        type: Button,
        tooltip: "關閉按鈕（×）"
    } )
    private m_closeBtn: Button = null;

    /** @ch 光效節點 */
    @property( {
        type: Node,
        tooltip: "光效節點"
    } )
    private m_lightNode: Node = null;
    //#endregion 屬性

    //#region 私有變數
    /** @ch 三張卡片的倍率陣列，由 Init 傳入，Label 顯示值 = Bet × rate */
    private m_multiplierRates: number[] = [];

    /** @ch 從 newBottombarManager 同步的可選 Bet 清單 */
    private m_betList: number[] = [];

    /** @ch 當前選中的 Bet 索引（對應 m_betList） */
    private m_betIdx: number = 0;

    /** @ch 當前選中的卡片索引；-1 表示尚未選擇 */
    private m_selectedIndex: number = -1;

    /** @ch 動畫播放中旗標，防止開/關動畫重疊觸發 */
    private m_isPlayingAnim: boolean = false;

    /** @ch ShowAndWait 的 resolve，等使用者操作後才回傳結果 */
    private m_waitResolve: ( ( result: ExtraBetWindowResult ) => void ) | null = null;
    //#endregion 私有變數

    //#region 方法
    /**
     * @ch 初始化跳窗（在 InitExtraBet 時呼叫）
     * @param multiplierRates 三個卡片的倍率陣列，Label 顯示值 = Bet × rate
     */
    Init( multiplierRates: number[] )
    {
        // BetList 在 ShowAndWait 時才同步（start 初期 newBottombarManager 可能尚未就緒）
        this.m_multiplierRates = multiplierRates;
    }

    /** @ch 綁定所有按鈕的觸控事件 */
    onLoad()
    {
        this.m_addBtn?.node.on( Node.EventType.TOUCH_END, this.AddBet, this );
        this.m_subBtn?.node.on( Node.EventType.TOUCH_END, this.SubBet, this );
        this.m_confirmBtn?.node.on( Node.EventType.TOUCH_END, this.OnConfirm, this );
        this.m_closeBtn?.node.on( Node.EventType.TOUCH_END, this.OnClose, this );
        for ( let i = 0; i < this.m_itemBtns.length; i++ )
        {
            const idx = i;
            this.m_itemBtns[ i ]?.node.on( Node.EventType.TOUCH_END, () => this.SelectItem( idx ), this );
        }
    }

    /** @ch 解綁所有按鈕的觸控事件，避免記憶體洩漏 */
    onDestroy()
    {
        this.StopLightBreathing();
        this.m_addBtn?.node.off( Node.EventType.TOUCH_END, this.AddBet, this );
        this.m_subBtn?.node.off( Node.EventType.TOUCH_END, this.SubBet, this );
        this.m_confirmBtn?.node.off( Node.EventType.TOUCH_END, this.OnConfirm, this );
        this.m_closeBtn?.node.off( Node.EventType.TOUCH_END, this.OnClose, this );
        for ( let i = 0; i < this.m_itemBtns.length; i++ )
        {
            this.m_itemBtns[ i ]?.node.targetOff( this );
        }
    }

    /**
     * @ch 顯示跳窗，等使用者按 Confirm 或 × 後回傳結果。
     * @param triggerCb 應 await 此方法，保持 m_ExtraBetAniPlaying=true 直到使用者操作完畢。
     */
    async ShowAndWait(): Promise<ExtraBetWindowResult>
    {
        // 若已有等待中的 resolve，先以取消結果回傳，避免懸掛 Promise
        if ( this.m_waitResolve )
        {
            this.m_waitResolve( { confirmed: false, type: 0 } );
            this.m_waitResolve = null;
        }

        if ( !this.m_viewNode.active )
        {
            await this.Show();
        }
        return new Promise<ExtraBetWindowResult>( ( resolve ) =>
        {
            this.m_waitResolve = resolve;
        } );
    }

    /**
     * @ch 播放開啟動畫並顯示介面，重置選中狀態與同步最新 BetList。
     * 動畫播放中或介面已顯示時直接 return。
     */
    private async Show()
    {
        const hideState = this.m_anim?.getState( AnimName.Hide );
        if ( this.m_isPlayingAnim || this.m_viewNode.active || hideState?.isPlaying ) return;

        // 重置選中狀態，同步最新 BetList
        this.m_selectedIndex = -1;
        this.UpdateSelectFrames();
        this.m_betList = newBottombarManager.GetBetList().slice();
        this.m_betIdx = newBottombarManager.GetNowBetIndex();
        if ( this.m_betIdx >= this.m_betList.length )
        {
            this.m_betIdx = this.m_betList.length - 1;
        }
        this.SetPrice();

        Tween.stopAllByTarget( this.node );
        this.m_isPlayingAnim = true;
        this.m_viewNode.active = true;
        this.m_anim?.play( AnimName.Show );
        const showState: AnimationState = this.m_anim?.getState( AnimName.Show );
        if ( showState )
        {
            await Define.Wait( this, showState.duration );
        }
        this.m_isPlayingAnim = false;
        this.StartLightBreathing();
    }

    /**
     * @ch 播放關閉動畫並隱藏介面。
     * 介面已隱藏或關閉動畫播放中時直接 return；若開啟動畫正在播放則先強制停止。
     */
    async Hide()
    {
        const hideState = this.m_anim?.getState( AnimName.Hide );
        if ( !this.m_viewNode.active || hideState?.isPlaying ) return;

        const showState = this.m_anim?.getState( AnimName.Show );
        if ( showState?.isPlaying )
        {
            showState.stop();
            this.m_isPlayingAnim = false;
        }

        this.StopLightBreathing();
        Tween.stopAllByTarget( this.node );
        this.m_isPlayingAnim = true;
        this.m_anim?.play( AnimName.Hide );
        const playingHideState = this.m_anim?.getState( AnimName.Hide );
        if ( playingHideState )
        {
            await Define.Wait( this, playingHideState.duration );
        }
        this.m_viewNode.active = false;
        this.m_isPlayingAnim = false;
    }

    /** @ch 將 Bet 索引往上加一（已到最大值則忽略），並更新所有價格 Label */
    AddBet()
    {
        if ( this.m_betIdx + 1 > this.m_betList.length - 1 ) return;
        AudioManager.Play( Define.AudioClips.COMMON_BTN );
        this.m_betIdx++;
        this.SetPrice();
    }

    /** @ch 將 Bet 索引往下減一（已到最小值則忽略），並更新所有價格 Label */
    SubBet()
    {
        if ( this.m_betIdx - 1 < 0 ) return;
        AudioManager.Play( Define.AudioClips.COMMON_BTN );
        this.m_betIdx--;
        this.SetPrice();
    }

    /**
     * @ch 根據當前 m_betIdx 更新 Bet Label 與三個卡片的金額 Label。
     * 卡片金額 = 當前 Bet × 對應倍率（m_multiplierRates[i]）。
     */
    private SetPrice()
    {
        const bet = this.m_betList[ this.m_betIdx ];
        if ( this.m_betLabel )
        {
            this.m_betLabel.string = tools.FormatNumberThousands( bet, tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT );
        }
        for ( let i = 0; i < this.m_itemLabels.length; i++ )
        {
            if ( this.m_itemLabels[ i ] && this.m_multiplierRates[ i ] !== undefined )
            {
                const value = tools.times( bet, this.m_multiplierRates[ i ] );
                this.m_itemLabels[ i ].string = tools.FormatNumberThousands( value, tools.FORMAT_NUMBER_TYPE.PERMANENT_DOT );
            }
        }
    }

    /**
     * @ch 選中指定卡片並更新選中框顯示。
     * 若點擊已選中的卡片則忽略（避免重複音效與重繪）。
     * @param index 卡片索引（0-based）
     */
    private SelectItem( index: number )
    {
        if ( this.m_selectedIndex === index ) return;
        AudioManager.Play( Define.AudioClips.COMMON_BTN );
        this.m_selectedIndex = index;
        this.UpdateSelectFrames();
    }

    /** @ch 依 m_selectedIndex 更新所有卡片選中框的 active 狀態（只顯示選中項） */
    private UpdateSelectFrames()
    {
        for ( let i = 0; i < this.m_itemSelectFrames.length; i++ )
        {
            if ( this.m_itemSelectFrames[ i ] )
            {
                this.m_itemSelectFrames[ i ].active = ( i === this.m_selectedIndex );
            }
        }
    }

    /**
     * @ch 啟動 m_lightNode 的呼吸動畫（參數見 LightBreathing 常數）。
     * 啟動前先清理舊 tween 並重置 scale，避免重複啟動造成抖動。
     */
    private StartLightBreathing()
    {
        if ( !this.m_lightNode ) return;
        const { HalfCycleSec, MinScale, MaxScale } = LightBreathing;
        Tween.stopAllByTarget( this.m_lightNode );
        this.m_lightNode.setScale( MinScale, MinScale, MinScale );
        tween( this.m_lightNode )
            .to( HalfCycleSec, { scale: new Vec3( MaxScale, MaxScale, MaxScale ) }, { easing: "sineInOut" } )
            .to( HalfCycleSec, { scale: new Vec3( MinScale, MinScale, MinScale ) }, { easing: "sineInOut" } )
            .union()
            .repeatForever()
            .start();
    }

    /** @ch 停止 m_lightNode 的呼吸動畫並重置 scale 為 MinScale。 */
    private StopLightBreathing()
    {
        if ( !this.m_lightNode ) return;
        const { MinScale } = LightBreathing;
        Tween.stopAllByTarget( this.m_lightNode );
        this.m_lightNode.setScale( MinScale, MinScale, MinScale );
    }

    /**
     * @ch 確認按鈕處理：關閉介面後，若有選中卡片則同步 Bet 至 bottombar，
     * 並透過 m_waitResolve 回傳 { confirmed: true, type: selectedIndex+1 }；
     * 未選卡片時回傳 { confirmed: false, type: 0 }。
     */
    private async OnConfirm()
    {
        if ( this.m_isPlayingAnim ) return;
        AudioManager.Play( Define.AudioClips.COMMON_BTN );
        await this.Hide();
        const type = this.m_selectedIndex >= 0 ? this.m_selectedIndex + 1 : 0;
        const isConfirmed = this.m_selectedIndex >= 0;
        if ( isConfirmed )
        {
            newBottombarManager.SetNowBet( this.m_betList[ this.m_betIdx ] );
        }
        this.m_waitResolve?.( { confirmed: isConfirmed, type } );
        this.m_waitResolve = null;
    }

    /**
     * @ch 關閉按鈕（×）處理：關閉介面並透過 m_waitResolve 回傳
     * { confirmed: false, type: 0 }，表示使用者取消操作。
     */
    private async OnClose()
    {
        if ( this.m_isPlayingAnim ) return;
        AudioManager.Play( Define.AudioClips.COMMON_BTN );
        await this.Hide();
        this.m_waitResolve?.( { confirmed: false, type: 0 } );
        this.m_waitResolve = null;
    }
    //#endregion 方法
}

