async ExtendShowBar( goToExtend: boolean )
{
    if ( !this.m_canExtend ||
        tools.CheckSwitchOff( SwitchOffKeyDefine.CloseExtraBet ) )
    {
        return;
    }
    if ( newBottombarManager && !this.m_ExtraBetAniPlaying )
    {
        if ( goToExtend )
        {
            if ( !newBottombarManager.IsAutoSpin && !Define.IsUsingItem
                && !buyBonusManager.IsBuyBonus )
            {
                if ( !this.m_isExtendShowBar )
                {
                    this.m_isExtendShowBar = true;
                    newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_SPIN );
                    this.m_ExtraBetAniPlaying = true;
                    if ( this.m_multiExtraBetNode )
                    {
                        await this.PlayAnimation( this.m_multiExtraBetNode.getComponent( Animation ), "ExtraBet_Show" );
                    }
                    this.m_ExtraBetAniPlaying = false;
                    newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
                    if ( this.m_isExtra && this.m_multiExtraBetNode )
                    {
                        this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Active" );
                    }

                    // tween( this.node )
                    //     .call( () =>
                    //     {
                    //         this.ExtraBetAniPlaying = true;
                    //         // 規格：m_multiBtn_animationState 在表演的時候要鎖地bar
                    //         newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_SPIN );
                    //         this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Show" );
                    //     } )
                    //     .delay( DELAYTIME.EXTRABET_LOGO_OPEN )
                    //     .call( () =>
                    //     {
                    //         this.ExtraBetAniPlaying = false;

                    //         newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
                    //         if ( this.m_isExtra )
                    //         {
                    //             this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Active" );
                    //         }
                    //     } )
                    //     .start();
                }
            }
            else
            {
                msgBoxManager.ShowMessageBox( Define.StringKey.FREEWINCASH_PLAYING1 );
            }
        }
        else
        {
            if ( this.m_isExtendShowBar )
            {
                // 取消第一次展開Bar的Idle
                if ( this.m_firstShowBarTween !== null )
                {
                    this.m_firstShowBarTween.stop();
                    this.m_firstShowBarTween = null;
                }

                if ( !newBottombarManager.IsAutoSpin )
                {
                    // newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_SPIN );
                }
                // 說明
                if ( this.m_multiBtn_Tip )
                {
                    this.m_multiBtn_Tip.active = false;
                }
                this.m_ExtraBetAniPlaying = true;
                if ( this.m_multiExtraBetNode )
                {
                    await this.PlayAnimation( this.m_multiExtraBetNode.getComponent( Animation ), "ExtraBet_Close" );
                }
                this.m_ExtraBetAniPlaying = false;
                if ( !newBottombarManager.IsAutoSpin )
                {
                    // newBottombarManager.SetSpinState( SlotBottomBarState.IDLE );
                }
                if ( this.m_multiExtraBetNode )
                {
                    if ( this.m_isExtra )
                    {
                        this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_Active" );
                    }
                    else
                    {
                        this.m_multiExtraBetNode.getComponent( Animation ).play( "ExtraBet_OFF" );
                        let state = this.m_multiExtraBetNode.getComponent( Animation ).getState( "ExtraBet_OFF" );
                        state.setTime( state.duration );
                    }
                }
                this.m_isExtendShowBar = false;
                // tween( this.node )
                //     .call( () =>
                //     {
                //         this.ExtraBetAniPlaying = true;
                //         if ( !newBottombarManager.IsAutoSpin )
