    type: ExtraBetWindow,
    tooltip: "Extra Bet 兩步驟選擇跳窗"
} )
private m_extraBetWindow: ExtraBetWindow = null;

@property( {
    type: Animation,
    tooltip: "ExtraBet EX 節點(ExtraBetNode 根)的 Animation：兩步驟取消時補播 ExtraBet_OFF 熄滅發亮用"
} )
private a_extraBetAnimation: Animation = null;

input.old_string:
// 取消（未選/×/未選即 Confirm，confirmed=false）時：公版 ChangeBetMode 會在本
// callback 結束後無條件 play "ExtraBet_Active" 重新點亮 EX 按鈕（公版 :507 漏判
// m_isExtra，不可改公版）。此時 m_isExtra 已為 false，於次幀補呼叫公版自身的
// OnRotation() 會 play "ExtraBet_Stop" 把按鈕熄滅，蓋掉那次誤點亮。
if ( !confirmed ) {
    this.scheduleOnce( () => { this.m_extraBetComp?.OnRotation(); }, 0 );
}

input.new_string:
// 取消（未選/×/未選即 Confirm，confirmed=false）時：公版 ChangeBetMode 會在本
// callback 結束後無條件 play "ExtraBet_Active" 重新點亮 EX 按鈕（公版 :507 漏判
// m_isExtra，不可改公版）。於次幀（晚於公版那行）直接在 EX 節點 Animation 補播
// "ExtraBet_OFF" 並跳到結尾，蓋掉那次誤點亮、熄滅 FX 發亮（bar 維持展開不收回）。
// 註：公版 OnRotation 播的 "ExtraBet_Stop" 在本專案無對應 .anim，故直接控 Animation。
if ( !confirmed ) {
    this.scheduleOnce( () => {
        if ( this.a_extraBetAnimation ) {
            this.a_extraBetAnimation.play( "ExtraBet_OFF" );
            const state = this.a_extraBetAnimation.getState( "ExtraBet_OFF" );
            if ( state ) state.setTime( state.duration );
        }
    }, 0 );
}

